                , null
                , null
            );
            break;
        case 4:
            // 본선관리번호
            if (lc_odrKndCd.getValue() == "B4") {
                pWhere = "E";
            }
            else {
                pWhere = "I";
            }

            //pWhere = lc_odrKndCd.ValueOfIndex("fltrCd2", lc_odrKndCd.Index); 	// 수출입구분코드 : SD060 - 수입(I), 수출(E)
