            arrParam[0] = pCode;	// 본선관리번호
            arrParam[1] = pWhere;	// 수출입구분코드
            //rtnList = window.showModalDialog('/ds/op/wrkplan/stvwrkplan/op_204_01_07p.jsp?paramTitle=본선관리번호검색팝업',arrParam,"dialogWidth:900px; dialogHeight:400px; status:No");


