            rtnList = $c.win.openPopup("/ui/ds/op/wrkplan/stvwrkplan/op_204_01_07p.xml", options, paramObj);

            /******************
            *	본선관리번호 Return List
            ** rtnValues[0] //본선관리번호
            * rtnValues[1] //선박코드
            ** rtnValues[2] //선박명
            * rtnValues[3] //마감일자
            * rtnValues[4] //마감시간
            * rtnValues[5] //도착(입항)일자
