                    //hid_vsslNm.Text			= rtnList[2]; //선박명
                    //hid_portcnt.Text		= rtnList[9]; //선사항차
                    //hid_portCd.Text			= rtnList[11]; //항구코드

                    if (lc_odrKndCd.getValue() == DsConstants.ODR_KND_CD_IMP_GNRL_BULK_ODR) {
