                    }

                    //Line명과 선사거래처 가져오기
                    //if(!cfIsNull(ed_lineCd.Text))	f_openCommonPopUp(5, ed_lineCd.Text, "", "T", "F")

                    // 오더종류별 설정
                    if (lc_odrKndCd.getValue() == DsConstants.ODR_KND_CD_IMP_GNRL_BULK_ODR) {
                        // 수입일반오더인 경우
                        ed_closeDt.setValue(rtnList[5]); //입항일자
                        ed_closeHh.setValue(rtnList[6]); //입항시간
                    }
                }
            } else {
                if (lc_odrKndCd.getValue() == DsConstants.ODR_KND_CD_EXP_GNRL_BULK_ODR) {
                    // 벌크 수출 일반 오더인 경우
                    $c.gus.cfInitObjects([ed_cvsslMgntNo, hid_vsslCd, hid_portcnt,
                        ed_lineCd, ed_lineNm, ed_shpCoClntNm]);

                    $c.gus.cfInitHidVal([ed_cvsslMgntNo]);
                    hid_portCd.value = "";
                } else {
                    // 벌크 수출 일반 오더 가 아닌경우
                    $c.gus.cfInitObjects([ed_cvsslMgntNo,
                        ed_closeDt, ed_closeHh, ica_wrkStDt, ed_wrkStHh,
                        ed_dptWrkPlCd, ed_dptWrkPlNm, ed_lineCd, ed_lineNm, ed_shpCoClntNm]);
                    //hid_vsslCd, hid_portcnt,

                    $c.gus.cfInitHidVal([ed_cvsslMgntNo]);
                    hid_portCd.value = "";
                }

            }

            // 수입본선, 벌크 부두간 TS 오더인 경우선박코드,항차,항구 정보로 적하목록 BL 품명 정보를 조회한다.
            //f_chkBlList();
            break;
        case 5:
            // LINE 코드팝업
            rtnList = //cfCommonPopUp('retrieveLineInfoList_tpro'	// XML상의 SELECT ID
                udc_lineNm.cfCommonPopUp(scwin.udc_lineNm_callBackFunc
                    , pCode					// 화면에서의 ??? Code Element의	Value
                    , pName					// 화면에서의 ??? Name Element의	Value
                    , pClose					// 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
                    , null					// 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
                    , null					// Title순서
                    , null					// 보여주는 각 컬럼들의 폭
                    , null					// 컬럼중에서 숨기는	컬럼 지정
                    , null					// SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
                    , null					// POP-UP뛰을때 원도우의	사용자 정의	폭
                    , null					// POP-UP뛰을때 우도우의	사용자 정의	높이
                    , null					// 윈도우 위치 Y좌표
                    , null					// 윈도우 위치 X좌표
                    , null					// 중복체크여부	("F")
                    , pAllSearch					// 전체검색허용여부	("F")
                    , "LINE,LINE코드/명"				// POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
                    , null
                    , null
                );
            break;
        case 6:

            // 출발작업장 코드팝업
            pWhere = ",,,,,,," + ed_ctrtClntNo.getValue();
            rtnList = //cfCommonPopUp('retrieveWrkPlInfo_tpro1'	// XML상의 SELECT ID
                udc_dptWrkPlCd.cfCommonPopUp(scwin.udc_dptWrkPlCd_callBackFunc
                    , pCode					// 화면에서의 ??? Code Element의	Value
                    , pName					// 화면에서의 ??? Name Element의	Value
                    , pClose					// 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
