                    , null
                    , null
                );
            break;
        case 7:
            // 도착작업장 코드팝업
            pWhere = ",,,,,,," + ed_ctrtClntNo.Text;
            //rtnList = cfCommonPopUp('retrieveWrkPlInfo_tpro1'	// XML상의 SELECT ID
            udc_arvWrkPlCd.cfCommonPopUp(scwin.udc_arvWrkPlCd_callBackFunc
                , pCode					// 화면에서의 ??? Code Element의	Value
                , pName					// 화면에서의 ??? Name Element의	Value
                , pClose					// 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
                , null					// 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
                , null					// Title순서
                , null					// 보여주는 각 컬럼들의 폭
                , null					// 컬럼중에서 숨기는	컬럼 지정
                , pWhere					// SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
                , null					// POP-UP뛰을때 원도우의	사용자 정의	폭
                , null					// POP-UP뛰을때 우도우의	사용자 정의	높이
                , null					// 윈도우 위치 Y좌표
                , null					// 윈도우 위치 X좌표
                , null					// 중복체크여부	("F")
                , pAllSearch					// 전체검색허용여부	("F")
                , "도착지,도착지코드/명"				// POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
                , null
                , null
            );
            break;
        case 8:
            //pWhere = ",";
            // 요청 거래처코드팝업
            rtnList = //cfCommonPopUp('retrieveClntInfo_tpro' // XML상의 SELECT ID
                udc_reqClntNo.cfCommonPopUp(scwin.udc_reqClntNo_callBackFunc
                    , pCode                  // 화면에서의 ??? Code Element의  Value
                    , pName                  // 화면에서의 ??? Name Element의  Value
                    , pClose                 // 결과가 1건 일때  원도우를  AutoClose 여부    (T:Close,F:Opened)
                    , null                   // 검색 결과    컬럼의 보여주는    개수 (SELECT절의 순서) MAX:10 - default (2)
                    , null                   // Title순서
                    , null                   // 보여주는 각 컬럼들의 폭
                    , null                   // 컬럼중에서 숨기는    컬럼 지정
                    , null                 // SQL절의 WHERE절에    원하는 조건을 선택함 MAX:8개까지 가능
                    , null                   // POP-UP뛰을때 원도우의   사용자 정의  폭
                    , null                   // POP-UP뛰을때 우도우의   사용자 정의  높이
                    , null                   // 윈도우 위치 Y좌표
                    , null                   // 윈도우 위치 X좌표
                    , null                   // 중복체크여부   ("F")
                    , pAllSearch                 // 전체검색허용여부 ("F")
                    , "요청 거래처,요청처코드/명"               // POP-UP Window Title 검색어1,2    ("Win타이틀,첫번검색Nm,두번?검색Nm")
                    , null
                    , null
                );
            break;
        default:
            break;
    }
}


