scwin.f_openZipPopUpNew = async function (gubun, pClose) {
    var rtnList = new Array();
    let options = {
        id: "zipPop",
        type: "browserPopup",
        popupName: "주소찾기",
        width: 735,
        height: 400
    };

    let paramObj = {};
    let popupResult = await $c.win.openPopup("/ui/cm/zz/zipcodePopup.xml", options, paramObj);

    // Modal Dialog를 리턴값 없이 닫을 경우에 대비해
    if (popupResult != null) {
        if (rtnList[0] == "N/A") return; //
        if (gubun == 1) {
            ed_dptZip.setValue(popupResult.zip); //출발지 우편번호
            ed_dptDtl.focus();
        } else if (gubun == 2) {
            ed_arvZip.setValue(popupResult.zip); //도착지 우편번호
            ed_arvDtl.focus();
        }
    } else {
        if (gubun == 1) {
            ed_dptZip.setValue(""); //출발지 우편번호
        } else if (gubun == 2) {
            ed_arvZip.setValue(""); //도착지 우편번호
        }
    }
}

