// 추가오더 분할
scwin.btnAdd_onclick = function (e) {
    scwin.f_odrAdd();
};

scwin.f_odrAdd = function () {
    if (ds_order.getTotalRow() == 0) {
        ds_order.insertRow();
    } else {
        ds_order.removeAll();
        ds_order.setRowData(0, [{}]);
    }

    if (ed_odrNo.getValue() == "") {
        $c.win.alert("오더 생성 후 오더추가 기능을 사용하세요");
        return false;
    }
    if (ds_bulkOdrInfoDTO.getCellData(0, "odrDcsnYn") == "0") {
        $c.win.alert("오더 확정 후 오더추가 기능을 사용하세요");
        return false;
    }
    if (ds_bulkOdrCommList.getRowCount() != 1) {
        $c.win.alert("오더추가는 품명이 1개인 오더에 대해서만 진행 가능합니다.");
        return false;
    }
    if ($c.num.parseFloat(ed_addKg.getValue()) < 1000) {
        $c.win.alert("추가물량(Kg)에 1000보다 작은 값을 입력했습니다. 유효한 숫자를 입력해 주세요");
        ed_addKg.focus();
        return false;
    }

    ds_order.setJSON([{
        "odrNo": ed_odrNo.getValue(),
        "odrAddWt": ed_addKg.getValue(),
        "copyClsCd": "A"
    }]);
    //tr_odrCopy.Post();
    $c.sbm.execute(sbm_odrCopy);
};


