    ica_wrkEndDt.setValue($c.date.getServerDateTime("yyyyMMdd"));
    scwin.btn_flag = "CLEAR";

    $c.gus.cfEnableObjects([odrMainData, odrDetailData, btn_save, btn_commList]);
    $c.gus.cfDisableObjects([btn_clear, btn_update, btn_delete]);

    //내수 및 수출 오더에 대하여는 본선번호 disable img_PopUp3 본선번호 옆 img_PopUp4 본선번호 옆옆 이거 화면 없음
    if (lc_odrKndCd.getValue() == "B2") {
        $c.gus.cfEnableObjects([udc_cvsslMgntNo]);// 번호 이름이 아닌 udc로 해야 이미지도 막힘
    } else {
        $c.gus.cfDisableObjects([udc_cvsslMgntNo]);
    }

    //그리드 값 수정 가능
    gr_commList.setReadOnly("grid", false);
