}

// 저장하기 클릭시
scwin.btn_save_onclick = function (e) {
    scwin.f_save();
};

scwin.f_save = async function (e) {
    if (!await $c.gus.cfValidate([lc_odrKndCd, ed_ctrtClntNo, lc_ctrtNo, ed_reqClntNo, ed_dptZip, ed_arvZip])) {
        return;
    }

    if (lc_ctrtNo.getValue() && lc_ctrtNo.getValue().trim() == '선택') { //lc_ctrtNo.ValueOfIndex("ctrtNo", lc_ctrtNo.Index) == "선택"
        $c.win.alert($c.data.getMessage(MSG_CM_ERR_002, '계약번호')); //@은(는) 필수 입력 항목입니다
        lc_ctrtNo.focus();
        return false;
    }

    if (await $c.gus.cfIsNull(scwin.login_regBranCd)) {
        $c.win.alert($c.data.getMessage(MSG_CM_ERR_002 + "\n 사용자 정보[물류점소]를 확인하시기 바랍니다.", '등록점소코드'));
        return false;
    }

    if (!await $c.gus.cfValidate([ed_sellLodeptCd, ed_bilgLodeptCd, ed_dptWrkPlCd, ica_wrkStDt, ed_wrkStHh, ed_arvWrkPlCd, ica_wrkEndDt, ed_wrkEndHh])) {
        return;
    }


    // 출발작업일자가 도착작업일자보다 큰 경우
    if (ica_wrkStDt.getValue().trim() > ica_wrkEndDt.getValue().trim()) {
        $c.win.alert($c.data.getMessage(MSG_CM_ERR_057, "도착일자", "출발일자"));
        ica_wrkEndDt.focus();
        return false;
    }

    // 출발작업시간이 도착작업시간보다 큰 경우
    if (ica_wrkStDt.getValue().trim() == ica_wrkEndDt.getValue().trim() && ed_wrkStHh.getValue().trim() >= ed_wrkEndHh.getValue().trim()) {
        $c.win.alert($c.data.getMessage(MSG_CM_ERR_057, "도착시간", "출발시간"));
        ed_wrkEndHh.focus();
        return false;
    }


    //수량,중량 중의 하나이상은 0이 아니여야 한다.
    for (var i = 0; i < ds_bulkOdrCommList.getTotalRow(); i++) {
        if (eval(ds_bulkOdrCommList.getCellData(i, "qty")) == 0 &&
            eval(ds_bulkOdrCommList.getCellData(i, "grossWt")) == 0) {
            $c.win.alert("수량,중량 중의 하나이상은 0이 아니여야 합니다.");
            ds_bulkOdrCommList.setRowPosition(i);
            gr_commList.setFocusedCell(i, "qty", true); //gr_commList.SetColumn("qty");
            return;
        }
    }

    var tmpOdrKndValue = lc_odrKndCd.getValue() ? lc_odrKndCd.getValue() : ds_bulkOdrInfoDTO.getCellData(0, 'odrKndCd');

    ds_bulkOdrInfoDTO.setCellData(0, 'odrKndCd', tmpOdrKndValue);
    ds_bulkOdrInfoDTO.setCellData(0, 'sellYn', DsConstants.YN_YES); // AsIs hid로 고정값받아 연동 시키는 값
    ds_bulkOdrInfoDTO.setCellData(0, 'regBranCd', scwin.login_regBranCd); //등록점소 AsIs hid로 고정값받아 연동 시키는 값

    // 수출입구분 셋팅
    scwin.hid_impExpDomesticClsCd = scwin.f_setImpExpDomesticClsCd();//hid_impExpDomesticClsCd.value = f_setImpExpDomesticClsCd();   // 수출입내수구분코드
    if (!await scwin.f_gridValidChk()) {
        return;
    }

    if (await $c.win.confirm("저장하시겠습니까?")) {
        if (scwin.btn_flag == "UPDATE") {
            $c.sbm.execute(sbm_updateBulkOrder);
        } else {
            $c.sbm.execute(sbm_registBulkOrder);
        }
    }
};



//-------------------------------------------------------------------------
// 그리드 필수체크
//-------------------------------------------------------------------------
scwin.f_gridValidChk = async function () {

    //오더품목  필수 입력사항을 체크
    if (await $c.gus.cfValidate([gr_commList])) {
        // 작업경로 선택 사항 확인
        for (var idx = 0; idx < ds_bulkOdrCommList.getTotalRow(); idx++) {
            if (ds_bulkOdrCommList.getCellData(idx, "ctrtWrkPathSeq") <= 0) {
                //$c.win.alert([MSG_CM_WRN_007,"작업경로"]);
                $c.win.alert($c.data.getMessage(MSG_CM_WRN_007, "작업경로"));
                return false;
            }
        }
        return true;
    } else {
        return false;
    }
}

// 수출입구분 셋팅
scwin.f_setImpExpDomesticClsCd = function () {
    var impExpDomesticClsCd = "";
    var odrKndCd = lc_odrKndCd.getValue() //lc_odrKndCd.ValueOfIndex("code", lc_odrKndCd.Index);
    switch (odrKndCd) {
        case DsConstants.ODR_KND_CD_IMP_GNRL_BULK_ODR:	// 수입
            impExpDomesticClsCd = DsConstants.IMP_CD;
            break;
        case DsConstants.ODR_KND_CD_EXP_GNRL_BULK_ODR:	// 수출
            impExpDomesticClsCd = DsConstants.EXP_CD;
            break;
        default:	// 내수 : DsConstants.ODR_KND_CD_DOMESTIC_FCTY_CRRYOUT_ODR 외...
            impExpDomesticClsCd = DsConstants.DOMESTIC_CD;
            break;
    }
    return impExpDomesticClsCd;
};

scwin.f_chkOpenCommonPopUp = async function (inObj, pairObj, disGubun, isCode) {
    // 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
    if (!$c.gus.cfCanOpenPopup(inObj, pairObj)) {
        return;
    }
    // 짝이 되는 오브젝트의 값 제거
    $c.gus.cfClearPairObj(pairObj);
    // 검색어 세팅
    var pVal = $c.gus.cfGetValue(inObj);
    if (isCode == null || isCode == true) { // inObj가 코드 필드일 경우 팝업
        await scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'T');
    } else { // inObj가 코드명 필드일 경우 팝업
        await scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', 'T');
    }
}

